const Q_BIOLOGY_2007=[{"id": "objective>Biology>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organs that will be most useful to giant African rats in finding their way in underground habitats are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vibrissae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nostrils </div>", "<div style=\"font-family:Cambria;font-size:17px;\">eyes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tails</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vibrissae, or whiskers, are highly sensitive to touch, allowing animals to detect changes in their environment. This would be particularly useful for giant African rats in navigating their underground habitats, where visibility is limited.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The increasing order of the particle size in the following soil types is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clay → sand → silt → gravel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silt → sand → clay → gravel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay → silt → sand → gravel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silt → clay → sand → gravel</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The particle size of soil types increases in the order of clay, silt, sand, and gravel. Clay particles are the smallest, followed by silt, then sand, and finally gravel which has the largest particles. This is because clay particles are less than 0.002 mm, silt particles are 0.002 mm to 0.05 mm, sand particles are 0.05 mm to 2 mm, and gravel particles are greater than 2 mm in diameter.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The causative agent of bird flu is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protozoan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">virus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bacterium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fungus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bird flu, also known as avian influenza, is caused by a virus. Influenza viruses are a type of RNA virus that infects birds and can also infect humans and other animals. The virus is highly contagious among birds and can be deadly to them.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of parasitism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fungi growing on a dead tree branch </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A squirrel living in an abandoned nest of a bird</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mistletoe growing on an orange tree</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cattle egrets taking ticks from the body of cattle </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parasitism is a type of symbiotic relationship where one organism, the parasite, benefits at the expense of the other, the host. Mistletoe growing on an orange tree is an example of parasitism because the mistletoe (parasite) absorbs water and nutrients from the orange tree (host), which can harm or even kill the tree.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One adaptation shown by hydrophytes in fresh water habitats is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaves reduced to spines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor development of roots and xylem tissues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">waxy cuticle on shoot surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">well-developed roots and supporting system.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrophytes are plants that have adapted to living in aquatic environments. They often have poorly developed roots as they are not needed for water absorption and xylem tissues (which are responsible for the transport of water in plants) are also less developed because water can be absorbed directly from their surroundings.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A crucible of 5gm weighed 10gm after filling with fresh soil. It is then heated in an oven at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C for 1 hour. After cooling in a desiccator, the weight was 8gm. The percentage of water in the soil is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">80%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Weight of wet soil = 10gm - 5gm = 5gm <br/>  Weight of dry soil = 8gm - 5gm = 3 gm Percentage of water lost in the soil = 3gm/5gm × 100% = 60%  <br/>  Percentage left in the soil will be 100% - 60% = 40%</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest level of ecological organization is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">niche</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest level of ecological organization is the biosphere. The biosphere is the global sum of all ecosystems. It can also be termed as the zone of life on Earth, a closed system (apart from solar and cosmic radiation and heat from the interior of the Earth), and largely self-regulating.</div>", "topic": "ECOLOGY : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mangrove swamp in Nigeria is restricted to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea savanna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mangrove swamps are found in tropical and subtropical tidal areas. In Nigeria, they are found in the coastal region, which is part of the tropical rainforest, not in the savanna regions. Therefore, the correct answer is 'Tropical rainforest'.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A biotic factor which affects the distribution and abundance of organisms in a terrestrial habitat is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biotic factors are the living components of an ecosystem. They are the interactions between organisms. In this case, 'competition' is a biotic factor. Competition in biology is a type of interaction between species where the fitness of one is lowered by the presence of another. This can affect the distribution and abundance of organisms in a terrestrial habitat.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following Nigerian states can montane vegetation be found?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Taraba </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enugu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bauchi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plateau</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Montane vegetation is found in mountainous areas. In Nigeria, such vegetation can be found in the Plateau state, which is known for its cooler temperatures due to its high altitude. Therefore, the correct answer is 'Plateau'.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : HIGHLANDS OF MONTANE FORESTS AND GRASSLANDS"}, {"id": "objective>Biology>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The type of protective adaptation exhibited by the animal is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disruptive colouration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flash colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">countershading colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warning colouration</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Countershading, or Thayer's Law, is a form of camouflage. Countershading is the pattern of animal coloration in which an animal's pigmentation is darker on the upper side and lighter on the underside of the body. This pattern is found in many species of mammals, reptiles, birds, and fish. <br/>  <br/>  <br/> Countershading is a protective adaptation whereby an animal possess a darker colour in its dorsal side and a lighter colour in its ventral side. This helps the animal to camouflage and escape predation. This is exhibited by the animal in the above diagram.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labelled I is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photosensitive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">radiosensitive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemoreceptive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tactile </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> It is tactile because of its sensitive to touch. Tactile sensation in rats is mainly mediated through their whiskers, which are essential for navigation, object identification, and social interaction. Each whisker is anchored in a follicle rich in blood vessels and nerve endings, with mechanoreceptors detecting movements. Sensory information from whiskers is processed in the somatosensory cortex, specifically in regions called \"barrels,\" forming a detailed map for tactile perception. This system enables rats to explore and interact with their environment effectively.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors can bring about competition in a population?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dispersion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Emigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drought </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mortality</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Competition in a population can be brought about by various factors, one of which is scarcity of resources. Drought, which is a prolonged period of abnormally low rainfall leading to a shortage of water, can cause scarcity of resources. This scarcity can lead to competition among individuals in a population as they struggle to access the limited resources. The other options, dispersion, emigration, and mortality, do not directly cause competition.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory which supports the view that the large muscles developed by an athlete will be passed on to the offspring was proposed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lamarck</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Darwin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mendel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pasteur </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory that the large muscles developed by an athlete will be passed on to the offspring was proposed by Lamarck. This is known as Lamarck's theory of inheritance of acquired characteristics. According to this theory, an organism can change during its lifetime in response to its environment, and those changes are passed on to its offspring. This theory has been largely discredited in modern biology. The other options, Darwin, Mendel, and Pasteur, proposed different theories.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In lizards, the lowering of the gular fold is used to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catch insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract mates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defend their territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frighten enemies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In lizards, the lowering of the gular fold is used to attract mates. The gular fold is a part of a lizard's throat that can be expanded and contracted. During courtship, a male lizard may lower its gular fold to display its bright throat colors to attract a female. The other options, catch insects, defend their territory, and frighten enemies, are not the primary uses of the gular fold.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : LIZARD"}, {"id": "objective>Biology>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a fish that aestivates is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">croaker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lung fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cat fish </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aestivation is a state of animal dormancy, similar to hibernation, characterized by inactivity and a lowered metabolic rate, that is entered in response to high temperatures and arid conditions. The African lungfish is an example.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the organ directly on top of the kidney is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thyroid gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adrenal gland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prostate gland</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adrenal glands (also known as suprarenal glands) are endocrine glands that produce a variety of hormones including adrenaline and the steroids aldosterone and cortisol. They are found above the kidneys. Each gland has an outer cortex which produces steroid hormones and an inner medulla.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The diagram shows that the organisms are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hermaphrodite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">viviparous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oviparous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovoviviparous</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are oviparous. Oviparous animals are animals that lay eggs, with little or no other embryonic development within the mother. This is the reproductive method of most fish, amphibians, reptiles, all birds, the monotremes, and most insects, molluscs, and arachnids.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The breeding posture illustrated in the diagram is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">amplexus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">courtship display</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reproductive swimming</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amplexus is the mating position of frogs and toads, in which the male clasps the female about the back.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The photosynthetic pigments include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorophyll and carotenoids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloroplasts and cytochromes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">melanin and haemoglobin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cartenoids and haemoglobin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthetic pigments are molecules which are responsible for capturing light energy, which is then used to convert carbon dioxide and water into glucose. The main pigments are chlorophylls and carotenoids. Chlorophylls absorb blue and red light and reflect green light, which is why we see plants as green. Carotenoids absorb blue and green light and reflect yellow, orange and red light.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Insulin is produced by the endocrine organ labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insulin is produced by the endocrine organ labelled III, Insulin is produced by the pancreas</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the structure labelled I is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stimulate the development of secondary sexual characters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prepare the body for any emergency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintain proper glucose concentration in the blood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulate the activities of other endocrine glands</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is to regulate the activities of other endocrine glands. The part labelled I is the pituitary gland known as th master gland , it control all other endocrine glands in the body</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Monocots stems differ from dicot stems in that monocots have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no cambium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no pith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fewer vascular bundles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloems with parenchyma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monocots stems differ from dicot stems in that monocots have no cambium. The cambium is a layer of tissue in plants that provides undifferentiated cells for plant growth. It is responsible for secondary growth in plants, which leads to an increase in stem thickness. Monocots, however, do not have this secondary growth and therefore lack cambium.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The opening and closing of the stoma are regulated by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The opening and closing of the stoma are regulated by osmosis. Osmosis is the process by which water molecules move from an area of high concentration to an area of low concentration through a semi-permeable membrane. In the case of stomata, the guard cells surrounding the stomata swell or shrink due to osmosis, causing the stomata to open or close.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stunted growth and poor root development are a result of a deficiency in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stunted growth and poor root development are a result of a deficiency in phosphorus. Phosphorus is a vital nutrient for plants, playing a key role in energy transfer and storage, as well as in photosynthesis, respiration, and cell division. A deficiency in phosphorus can lead to stunted growth and poor root development.</div>", "topic": "NUTRITION : MINERAL REQUIREMENT"}, {"id": "objective>Biology>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas secretes enzymes for the digestion of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fats, proteins and carbohydrates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fats, vitamins and cellulose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fats, carbohydrates and vitamins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">proteins, cellulose and minerals</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pancreas secretes enzymes that aid in the digestion of fats, proteins, and carbohydrates. These enzymes include lipase (for fats), protease (for proteins), and amylase (for carbohydrates). Therefore, the correct answer is 'fats, proteins and carbohydrates'.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pineapple is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a dehiscent fruit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an aggregate fruit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a composite fruit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a simple fruit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pineapple is an example of a composite fruit, also known as a multiple fruit. This type of fruit develops from the merging of several ovaries that were separate in a single flower. Therefore, the correct answer is 'a composite fruit'.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of the movement of urea during urine formation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glomerulus → Bowman's capsule → convoluted tubule → Henle's loop → collecting tubule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glomerulus → Bowman's capsule → convoluted tubule →  convoluted tubule → collecting tubule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">convoluted tubule → glomerulus → Henle's loop → Bowman's capsule → collecting tubule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">convoluted tubule → Bowman's capsule → Henle's loop → glomerulus → collecting tubule </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct sequence of the movement of urea during urine formation is from the glomerulus to the Bowman's capsule, then to the convoluted tubule, Henle's loop, and finally the collecting tubule. The glomerulus filters the blood, and the filtrate, which contains urea, is collected in the Bowman's capsule. The filtrate then moves through the convoluted tubule and Henle's loop where reabsorption of water and solutes occurs. The remaining filtrate, now urine, moves to the collecting tubule. Therefore, the correct answer is 'glomerulus → Bowman's capsule → convoluted tubule → Henle's loop → collecting tubule'.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Oxygenated blood is pumped to the entire body from the part labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled IV is known as left verticles. Oxygenated blood is pumped from the left ventricle of the heart into the aorta. The aorta then distributes this blood throughout the body via its branches, ensuring that all tissues and organs receive oxygen and nutrients essential for their function.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled I is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pulmonary artery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vena cava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aorta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bicuspid valve</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the pulmonary artery. The part labelled I is the pulmonary artery. The pulmonary artery carries deoxygenated blood from the right ventricle to the lungs, where it splits into the left and right pulmonary arteries. Its primary function is to transport blood to the lungs for oxygenation. <br/> <img src=\"2007/GEF6N8.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> </div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The waste product of plants used in the conversion of hide to leather is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkaloid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tannin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The waste product of plants used in the conversion of hide to leather is tannin. Tannin is a type of polyphenolic compound found in various plant tissues. It is used in the leather industry for tanning hides and skins, a process that converts the raw hide into a material that will not decompose and is suitable for a variety of end applications.</div>", "topic": "EXCRETION : EXCRETORY PRODUCTS OF PLANTS"}, {"id": "objective>Biology>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following uses diffusion as the principal method of gaseous exchange?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lizard </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grasshopper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rat </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Earthworm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Earthworms use diffusion as the principal method of gaseous exchange. They breathe through their skin, where oxygen from the environment diffuses directly into their bloodstream and carbon dioxide diffuses out. This process is facilitated by the moist mucus that covers the earthworm's skin.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The experiment demonstrates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">geotropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thigmotropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phototropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrotropism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It demonstrates geotropism. It is a turning or growth movement by a plant or fungus in response to gravity. It is a general feature of all higher and many lower plants as well as other organisms. <br/> Geotropism is the directional growth of parts of plant in response to gravity. This experiment demonstrate geotropism showing that the root undergoes positive geotropism (towards gravity) and the stem undergoes negative geotropism (against gravity)</div>", "topic": "SUPPORT AND MOVEMENT : TROPIC TACTIC NASTIC AND SLEEP MOVEMENTS IN PLANTS"}, {"id": "objective>Biology>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part marked I will contain a high concentration of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ascorbic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abscisic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">auxin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part marked I will contain a high concentration of auxin. causes the fast  growth of shoot.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the most primitive respiratory system?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Snail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Insect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mouse</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Snails have the most primitive respiratory system among the options provided. They breathe using a pallial lung, which is a type of lung that is developed from the mantle cavity. This is a simple and primitive system compared to the more complex respiratory systems of fish (gills), insects (tracheal system), and mice (lungs).</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled IV is responsible for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmoregulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ingestion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">locomotion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Osmoregulation is the active regulation of the osmotic pressure of an organism's fluids to maintain the homeostasis of the organism's water content; that is, it keeps the organism's fluids from becoming too diluted or too concentrated. The part labelled IV is the contractile vacuole. In a paramecium, osmoregulation is primarily managed by the contractile vacuole. The contractile vacuole is a specialized organelle responsible for regulating water intake and expulsion to maintain proper osmotic balance within the cell. It works by accumulating excess water that enters the cell through osmosis and then periodically expelling this water to prevent the cell from bursting due to osmotic pressure.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The organelle responsible for sexual reproduction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">III. The parts labelled II and III are the macronucleus and micronucleus respectively. Paramecium typically has one macronucleus and one or more micronuclei. The macronucleus is responsible for general cell functions, while micronuclei are involved in genetic exchange during conjugation, a form of sexual reproduction in Paramecium. Therefore, the organelle responsible for sexual reproduction is III</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A water medium is necessary for fertilization in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fungi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conifers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ferns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">angiosperms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ferns are a type of plant that require a water medium for fertilization. This is because their sperm cells are flagellated and need water to swim to the egg cells for fertilization to occur. Fungi, conifers, and angiosperms do not require a water medium for fertilization.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chromosomes of members of the kingdom Monera are within the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nucleoplasm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cytoplasm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleolus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Members of the kingdom Monera, which includes bacteria, do not have a true nucleus. Instead, their genetic material, or chromosomes, are found within the cytoplasm of the cell. This is a key characteristic that distinguishes them from eukaryotic organisms, which have a nucleus that houses their genetic material.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : MONERA"}, {"id": "objective>Biology>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram to answer the question that follows. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The organelle responsible for heredity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">III is the chromosome. The part labelled III is the chromosome. <br/> Chromosomes play a crucial role in heredity by carrying genetic information from one generation to the next. Chromosomes are responsible for heredity by: <br/>  <br/> - Carrying genes that code for specific traits <br/> - Replicating and passing on genetic information during cell division <br/> - Pairing and recombining genetic material to increase diversity <br/> - Determining the expression of traits and characteristics <br/>  <br/> This process ensures that the genetic information is transmitted from one generation to the next, making chromosomes the fundamental units of heredity.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram to answer the question that follows. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled I is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nuclear membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endoplasmic reticulum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plasmallema</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">plasmallema. The part labeled I is the plasmallema. The plasmalemma (cell membrane) is a thin, semi-permeable membrane that: <br/>  <br/> - Separates the cell from its environment <br/> - Protects the cell from harm <br/> - Regulates the movement of materials in and out <br/> - Receives and transmits cell signals <br/> - Facilitates cell adhesion <br/>  <br/> It is composed of a phospholipid bilayer with embedded proteins, and its functions are essential for maintaining cellular integrity and homeostasis.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of shedding the exoskeleton of an arthropod is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metamorphosis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">instar formation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ecdysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tagmosis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecdysis is the process of shedding the exoskeleton in arthropods. This is a necessary process as the exoskeleton is rigid and cannot grow with the organism. Therefore, the organism must periodically shed its exoskeleton and form a new one that is larger to accommodate its growth. Metamorphosis refers to the process of transformation from an immature form to an adult form in two or more distinct stages. Instar formation refers to the stages between each moulting in the life cycle of insects and other arthropods. Tagmosis is the fusion of segments into functional units.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is common to the mosquito housefly and blackfly?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They undergo complete metamorphosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are parasites of man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their immature stages are aquatic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their adults have two pairs of wings </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mosquitoes, houseflies, and blackflies all undergo complete metamorphosis. This means they go through four distinct stages of life: egg, larva, pupa, and adult. Not all of these insects have aquatic immature stages, are parasites of man, or have two pairs of wings.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The process illustrated is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gametogenesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sporulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sexual reproduction in Spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sexual reproduction in Rhizopus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process illustrated in the diagram is sexual reproduction in Rhizopus.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structure labelled I is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sporangium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hypha</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zygospore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conidiospore</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the zygospore. The part labeled I is the zygospore. The zygospore of Rhizopus: <br/>  <br/> - Is a large, spherical or oval-shaped cell with a thick, multilayered wall <br/> - Contains multiple nuclei and abundant cytoplasm <br/> - Results from sexual reproduction, formed by fusion of two haploid nuclei <br/> - Serves as a survival structure, tolerating adverse conditions <br/> - Remains dormant until favorable conditions return <br/> - Germinates to produce a new haploid generation, restarting the life cycle. <br/>  <br/> In short, the zygospore is a resilient, protective structure ensuring Rhizopus' survival and propagation.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An accurate identification of a rapist can be carried out by conducting a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">RNA analysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">DNA analysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood group test</div>", "<div style=\"font-family:Cambria;font-size:17px;\">behavioural traits test</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">DNA analysis is the most accurate method for identifying a rapist. This is because each person's DNA is unique to them (except in the case of identical twins). A DNA sample can be obtained from body fluids, hair, or skin cells left at the crime scene. RNA analysis, blood group tests, and behavioural traits tests are not as accurate or reliable.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the dogs are offspring of a monohybrid cross and the gene G for grey head is dominant over its allele g, the individual whose genotype is likely to be gg is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the dogs are offspring of a monohybrid cross and the gene G for grey head is dominant over its allele g, the individual whose genotype is likely to be gg is IV.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following will be true of dog II which lost its tail in an accident if it mates with dog III?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">None of its offspring will be born without a tail </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/4 of its offspring will be born without tails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all of its offspring will be born without tails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4 of its offspring will be born without tails </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">None of its offspring will be born without a tail.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is <strong>true</strong> of cloning?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It is welcomed as an ethically and morally sound science</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only one cell of the original organism is needed to initiate the process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The clone is similar to but not exactly like the original organism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It involves the asexual multiplication of the tissues of the original organism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The clone is similar to but not exactly like the original organism.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a sex-linked trait is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ability to grow long hair in females</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour of the skin in humans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ability to roll the tongue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">haemophilia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sex-linked traits are those that are associated with genes found on sex chromosomes. Haemophilia is a sex-linked trait because the gene that causes it is located on the X chromosome, which corresponds to option 4. The other options are incorrect because they are not associated with genes on the sex chromosomes.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}];
